from flask import redirect, url_for

def login_redirect(user):
    """
    Redirects users to their intended destination after authentication.

    Args:
        user: The authenticated user object.

    Returns:
        A Flask redirect object.
    """

    # Get the user's intended destination from their session or other storage mechanism
    destination = user.session.get('destination')

    # Redirect the user to their destination
    return redirect(destination or url_for('home'))